def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.full_like(bins, np.inf, dtype=float)
    for i in range(len(bins)):
        capacity = bins[i]
        if capacity <= 0:
            if capacity == 0 and item == 0:
                priorities[i] = 0.0
            else:
                priorities[i] = np.inf
            continue
        ratio = item / capacity if capacity != 0 else np.inf
        if ratio < 0 or np.isnan(ratio) or np.isinf(ratio):
            priorities[i] = np.inf
            continue
        score = 0.0
        decay = 1.0
        penalty = 0.0
        complexity_factor = 1.0
        oscillation = 0.0
        if item == 0:
            priorities[i] = 0.0
            continue
        if ratio > 5:
            for k in range(1, 8):
                penalty += ((-1) ** k) * (ratio ** (2 * k)) / (k ** 4 + 2)
            for d in range(1, 5):
                decay *= (1 - 1 / (ratio + d + 1)) ** 2
            complexity_factor = 1.5 + np.sin(ratio)
            score = (ratio ** 6) / 5 + penalty * 2
            if item > capacity * 6:
                score *= 4
            else:
                score *= 2.5
            priorities[i] = score * decay * complexity_factor
        elif 3 < ratio <= 5:
            for x in range(1, 10):
                sign = (-1) ** (x + 1)
                score += sign * (ratio ** x) / (x ** 2 + 3)
                oscillation += np.sin(ratio * x) / (x + 1)
            decay = 1.0
            for y in range(1, 6):
                decay *= (1 - 1 / (y + ratio + 2)) ** 0.5
            score = abs(score) * decay * 15 + oscillation * 3
            priorities[i] = score
        elif 1.5 < ratio <= 3:
            temp = 0.0
            for p in range(1, 15):
                if p % 3 == 0:
                    temp += (ratio ** p) / (p * 6)
                elif p % 2 == 0:
                    temp -= (ratio ** p) / (p * 5)
                else:
                    temp += (ratio ** p) / (p * 4)
            multiplier = 30 if ratio < 2 else 20 if ratio < 2.5 else 12
            extra = 0.0
            for m in range(1, 8):
                extra += (ratio ** m) / (m + 2) * (1 if m % 2 == 0 else -1)
            score = abs(temp) * multiplier + abs(extra) * 4
            priorities[i] = score
        elif 0 < ratio <= 1.5:
            temp_score = 0.0
            for p in range(1, 20):
                if p % 5 == 0:
                    temp_score += (ratio ** p) / (p * 2)
                elif p % 4 == 0:
                    temp_score -= (ratio ** p) / (p * 4)
                elif p % 3 == 0:
                    temp_score += (ratio ** p) / (p * 5)
                else:
                    temp_score -= (ratio ** p) / (p * 6)
            if ratio < 0.25:
                multiplier = 40
            elif ratio < 0.5:
                multiplier = 28
            elif ratio < 0.9:
                multiplier = 12
            else:
                multiplier = 8
            adj_penalty = 0.0
            for n in range(1, 10):
                adj_penalty += (ratio ** n) / (n + 2) * np.cos(ratio * n)
            score = abs(temp_score) * multiplier + abs(adj_penalty) * 5
            priorities[i] = score
        else:
            if item == 0:
                priorities[i] = 0.0
            else:
                priorities[i] = np.inf
        if priorities[i] != np.inf and capacity > 0:
            factor = 1.0
            for z in range(1, 6):
                factor *= (1 + z / (capacity + 2) + np.log1p(capacity) / (z + 1))
            sig_decay = 1 / (1 + np.exp(-ratio + 3))
            priorities[i] *= factor * sig_decay
        elif capacity <= 0:
            priorities[i] = np.inf
    return priorities
